async (params, browser) => {
  // Open page
  await browser.open(`https://huggingface.co/spaces/${params.space_id}`)

  // Wait for content
  await browser.waitForSelector('h1, main, iframe', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const title = document.querySelector('h1')?.textContent?.trim()||''; const desc = document.querySelector('main p')?.textContent?.trim()||''; const tags = Array.from(document.querySelectorAll('a[href*="/spaces?"]')).slice(0,10).map(t=>t.textContent.trim()); const sdkEl = document.querySelector('a[href*="/spaces?sdk="], a[href*="sdk:"]'); const sdk = sdkEl?.textContent?.trim()||''; const likesEl = document.querySelector('button[title*="Like"], button[title*="like"]'); const likes = likesEl?.textContent?.trim()||''; const linkedModels = Array.from(document.querySelectorAll('a[href]:not([href*="spaces"])')).filter(a => { const h = a.getAttribute('href')||''; return h.match(/^\/[^/]+\/[^/]+$/) && !h.includes('/spaces/') && !h.includes('/datasets/'); }).slice(0,5).map(a => ({ name: a.textContent.trim(), url: 'https://huggingface.co' + a.getAttribute('href') })); return { title, description: desc, tags, sdk, likes, linked_models: linkedModels, url: window.location.href }`)

  return page_data
}
